import { useState, useCallback, useEffect } from "react";
import { PageShell } from "@/components/orderly/PageShell";
import {
  Info,
  ImagePlus,
  Trash2,
  Eye,
  EyeOff,
  Plus,
  CheckCircle,
} from "lucide-react";
import { useTranslation } from "@/i18n";
import { storageKey } from "@/utils/storage";

const MAX_POSTERS = 8;

function fileToBase64(file: File): Promise<string> {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => resolve(reader.result as string);
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
}

export default function Page() {
  const { t } = useTranslation();
  const [posters, setPosters] = useState<string[]>([]);
  const [showPreview, setShowPreview] = useState(false);
  const [toast, setToast] = useState<string | null>(null);
  const [previewIndex, setPreviewIndex] = useState(0);

  useEffect(() => {
    const stored = localStorage.getItem(storageKey("orderlyPnlPosters"));
    if (stored) {
      try {
        setPosters(JSON.parse(stored) as string[]);
      } catch {}
    }
  }, []);

  const persist = useCallback((next: string[]) => {
    setPosters(next);
    if (typeof window !== "undefined") {
      localStorage.setItem(
        storageKey("orderlyPnlPosters"),
        JSON.stringify(next)
      );
    }
  }, []);

  function showToast(message: string) {
    setToast(message);
    setTimeout(() => setToast(null), 3000);
  }

  async function handleFileChange(index: number, file: File | null) {
    if (!file) return;
    try {
      const base64 = await fileToBase64(file);
      const next = [...posters];
      next[index] = base64;
      persist(next);
    } catch {
      showToast(t("pnlPosters.failedToReadImage"));
    }
  }

  function addPoster() {
    if (posters.length < MAX_POSTERS) {
      persist([...posters, ""]);
    }
  }

  function removePoster(index: number) {
    const next = posters.filter((_, i) => i !== index);
    persist(next);
    if (previewIndex >= next.length && next.length > 0) {
      setPreviewIndex(next.length - 1);
    }
  }

  const previewBackground = posters[previewIndex] || null;

  return (
    <PageShell pageTitle="PnL Posters">
      <div className="rounded-xl border border-(--line-subtle) bg-(--bg-surface-primary) p-6">
        <div className="mb-6 flex items-center justify-between">
          {posters.length < MAX_POSTERS && (
            <button
              type="button"
              onClick={addPoster}
              className="inline-flex items-center gap-1.5 rounded-lg border border-(--line-subtle) bg-(--bg-surface-secondary) px-3 py-2 text-sm font-medium text-(--fg-primary) transition-colors hover:bg-(--bg-hover)"
            >
              <Plus className="h-4 w-4" />
              Add poster
            </button>
          )}
        </div>

        {posters.length === 0 ? (
          <div className="mb-6 rounded-lg border border-(--line-subtle) bg-(--bg-surface-secondary) p-8 text-center">
            <div className="mx-auto mb-3 flex h-12 w-12 items-center justify-center rounded-full bg-(--bg-hover) text-(--fg-secondary)">
              <ImagePlus className="h-6 w-6" />
            </div>
            <p className="text-sm text-(--fg-secondary)">
              No posters uploaded yet.
            </p>
            <button
              type="button"
              onClick={addPoster}
              className="mt-4 inline-flex items-center gap-2 rounded-full px-5 py-2.5 text-sm font-medium text-(--fg-primary) transition-opacity hover:opacity-90"
              style={{ background: "var(--bg-brand-grad)" }}
            >
              <Plus className="h-4 w-4" />
              Add first poster
            </button>
          </div>
        ) : (
          <div className="mb-6 grid grid-cols-1 gap-4 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4">
            {posters.map((poster, index) => (
              <div
                key={index}
                className="rounded-lg border border-(--line-subtle) bg-(--bg-surface-secondary) p-3"
              >
                <div className="mb-2 flex items-center justify-between">
                  <span className="text-sm font-medium text-(--fg-primary)">
                    Poster {index + 1}
                  </span>
                  <button
                    type="button"
                    onClick={() => removePoster(index)}
                    className="inline-flex items-center gap-1 text-xs text-[#FF6390] transition-colors hover:text-[#FF6390]/80"
                  >
                    <Trash2 className="h-3.5 w-3.5" />
                    Remove
                  </button>
                </div>

                <label className="group relative flex aspect-4/3 w-full cursor-pointer flex-col items-center justify-center overflow-hidden rounded-lg border border-dashed border-(--line-subtle) bg-(--bg-input) transition-colors hover:border-(--line-brand) hover:bg-(--bg-hover)">
                  {poster ? (
                    <img
                      src={poster}
                      alt={`Poster ${index + 1}`}
                      className="h-full w-full object-cover"
                    />
                  ) : (
                    <>
                      <ImagePlus className="mb-2 h-6 w-6 text-(--fg-secondary)" />
                      <span className="text-xs text-(--fg-secondary)">
                        Click or drag image
                      </span>
                    </>
                  )}
                  <input
                    type="file"
                    accept="image/*"
                    onChange={e =>
                      handleFileChange(index, e.target.files?.[0] || null)
                    }
                    className="absolute inset-0 cursor-pointer opacity-0"
                  />
                </label>
              </div>
            ))}
          </div>
        )}

        {posters.length > 0 && posters.length < MAX_POSTERS && (
          <div className="mb-6 text-center">
            <button
              type="button"
              onClick={addPoster}
              className="inline-flex items-center gap-1.5 rounded-lg border border-(--line-subtle) bg-(--bg-surface-secondary) px-3 py-2 text-sm font-medium text-(--fg-primary) transition-colors hover:bg-(--bg-hover)"
            >
              <Plus className="h-4 w-4" />
              Add another poster ({posters.length}/{MAX_POSTERS})
            </button>
          </div>
        )}

        <div className="mb-6 rounded-lg border border-(--line-subtle) bg-(--bg-surface-secondary) p-4">
          <div className="mb-3 flex items-center gap-2">
            <Info className="h-4 w-4 text-(--fg-brand)" />
            <span className="text-sm font-medium text-(--fg-primary)">
              Design guidelines
            </span>
          </div>
          <ul className="space-y-2 text-sm text-(--fg-secondary)">
            <li className="flex items-start gap-2">
              <CheckCircle className="mt-0.5 h-3.5 w-3.5 shrink-0 text-[#1DF6B5]" />
              Use a dark background area so PnL text remains readable.
            </li>
            <li className="flex items-start gap-2">
              <CheckCircle className="mt-0.5 h-3.5 w-3.5 shrink-0 text-[#1DF6B5]" />
              Ensure high contrast for any text overlaid by the share widget.
            </li>
            <li className="flex items-start gap-2">
              <CheckCircle className="mt-0.5 h-3.5 w-3.5 shrink-0 text-[#1DF6B5]" />
              Keep visual balance — avoid busy patterns near the center.
            </li>
            <li className="flex items-start gap-2">
              <CheckCircle className="mt-0.5 h-3.5 w-3.5 shrink-0 text-[#1DF6B5]" />
              Recommended format: PNG or JPG, 1200x900 or similar 4:3 ratio.
            </li>
          </ul>
          <p className="mt-3 text-xs text-(--fg-placeholder)">
            Custom backgrounds are optional. If none are provided, the default
            gradient will be used.
          </p>
        </div>

        <div className="border-t border-(--line-subtle) pt-4">
          <button
            type="button"
            onClick={() => setShowPreview(s => !s)}
            className="inline-flex items-center gap-2 rounded-lg border border-(--line-subtle) bg-(--bg-surface-secondary) px-4 py-2 text-sm font-medium text-(--fg-primary) transition-colors hover:bg-(--bg-hover)"
          >
            {showPreview ? (
              <EyeOff className="h-4 w-4" />
            ) : (
              <Eye className="h-4 w-4" />
            )}
            {showPreview ? "Hide preview" : "Show PnL preview"}
          </button>

          {showPreview && (
            <div className="mt-4">
              {posters.filter(Boolean).length > 1 && (
                <div className="mb-3 flex flex-wrap gap-2">
                  {posters.map((p, i) =>
                    p ? (
                      <button
                        key={i}
                        type="button"
                        onClick={() => setPreviewIndex(i)}
                        className={`rounded-md border px-2 py-1 text-xs transition-colors ${
                          previewIndex === i
                            ? "border-(--line-brand) bg-[rgba(188,135,255,0.12)] text-(--fg-brand)"
                            : "border-(--line-subtle) bg-(--bg-input) text-(--fg-secondary) hover:bg-(--bg-hover)"
                        }`}
                      >
                        Poster {i + 1}
                      </button>
                    ) : null
                  )}
                </div>
              )}
              <div
                className="relative overflow-hidden rounded-xl border border-(--line-subtle) p-6"
                style={{
                  background: previewBackground
                    ? `url(${previewBackground}) center/cover no-repeat`
                    : "linear-gradient(135deg, #1a0b2e 0%, #2d1b4e 100%)",
                }}
              >
                <div className="absolute inset-0 bg-black/40" />
                <div className="relative mx-auto max-w-sm rounded-xl border border-white/10 bg-black/60 p-5 backdrop-blur-sm">
                  <div className="mb-3 flex items-center justify-between">
                    <span className="text-xs text-white/70">PERP_ETH_USDC</span>
                    <span className="rounded-full bg-[#1DF6B5]/20 px-2 py-0.5 text-xs font-medium text-[#1DF6B5]">
                      LONG
                    </span>
                  </div>
                  <div className="mb-1 text-3xl font-bold text-white">
                    +122.00%
                  </div>
                  <div className="mb-4 text-sm text-white/70">ROI</div>
                  <div className="space-y-1 text-sm">
                    <div className="flex justify-between">
                      <span className="text-white/60">Open Price</span>
                      <span className="text-white">$2,518.74</span>
                    </div>
                    <div className="flex justify-between">
                      <span className="text-white/60">Mark Price</span>
                      <span className="text-white">$2,518.81</span>
                    </div>
                    <div className="flex justify-between">
                      <span className="text-white/60">Quantity</span>
                      <span className="text-white">0.0794</span>
                    </div>
                    <div className="flex justify-between">
                      <span className="text-white/60">Leverage</span>
                      <span className="text-white">10x</span>
                    </div>
                  </div>
                  <div className="mt-4 border-t border-white/10 pt-3 text-center text-xs text-white/50">
                    Shared from My DEX
                  </div>
                </div>
              </div>
            </div>
          )}
        </div>
      </div>

      {toast && (
        <div className="fixed bottom-5 left-1/2 z-100 -translate-x-1/2 rounded-full border border-(--line-brand) bg-(--bg-surface-primary) px-5 py-2.5 text-sm font-medium text-(--fg-primary) shadow-xl">
          {toast}
        </div>
      )}
    </PageShell>
  );
}
